tf.s3_bucket(rust_lambda_artifacts) { bucket = "my-rust-lambda"; versioning { enabled = true } }
tf.lambda_function(my_lambda) {
  function_name = "rust-server"
  role = aws_iam_role.lambda_exec.arn
  handler = "main:main"
  source_code_hash = file_sha256()
}
